/// Shareable, thread-safe handle to a user-provided HTML visitor implementation.
///
/// Pass an instance wrapped in this handle to `ConversionOptions` to
/// customise how the HTML document is traversed and converted to Markdown.
/// The handle may be cloned and shared across threads without additional
/// synchronisation on the caller's side.
#[derive(Clone)]
#[wasm_bindgen]
pub struct WasmVisitorHandle {
    pub(crate) inner: Arc<html_to_markdown_rs::VisitorHandle>,
}

#[cfg(target_arch = "wasm32")]
#[wasm_bindgen]
impl WasmVisitorHandle {
    #[wasm_bindgen(constructor)]
    pub fn new(visitor: wasm_bindgen::JsValue) -> WasmVisitorHandle {
        let bridge = __alef_wasm_bridge_htmlvisitor::WasmHtmlVisitorBridge::new(visitor);
        let handle = std::sync::Arc::new(std::sync::Mutex::new(bridge));
        Self {
            inner: std::sync::Arc::new(handle),
        }
    }
}

/// Context information passed to all visitor methods.
///
/// Provides comprehensive metadata about the current node being visited,
/// including its type, tag name, position in the DOM tree, and parent context.
///
/// ## Attributes
///
/// Access attributes via `NodeContext.attributes`, which returns
/// `&BTreeMap<String, String>`. When the context was built with
/// `NodeContext.with_lazy_attributes` (the hot path inside the converter),
/// the map is only materialized on the first call — if the visitor never reads
/// attributes, the allocation is skipped.
///
/// ## Lifetimes
///
/// String fields use `Cow<'_, str>` so the converter can pass slices directly
/// out of the parsed DOM without allocating. Visitor implementations that need
/// to outlive the callback should call `NodeContext.into_owned`.
#[derive(Clone, Default)]
#[wasm_bindgen]
pub struct WasmNodeContext {
    node_type: WasmNodeType,
    tag_name: String,
    depth: usize,
    index_in_parent: usize,
    parent_tag: Option<String>,
    is_inline: bool,
}

#[wasm_bindgen]
impl WasmNodeContext {
    #[allow(non_snake_case)]
    #[wasm_bindgen(constructor)]
    pub fn new(
        nodeType: WasmNodeType,
        tagName: String,
        depth: usize,
        indexInParent: usize,
        isInline: bool,
        parentTag: Option<String>,
    ) -> WasmNodeContext {
        WasmNodeContext {
            node_type: nodeType,
            tag_name: tagName,
            depth,
            index_in_parent: indexInParent,
            parent_tag: parentTag,
            is_inline: isInline,
        }
    }

    #[wasm_bindgen]
    #[allow(clippy::should_implement_trait)]
    pub fn default() -> WasmNodeContext {
        <WasmNodeContext as ::core::default::Default>::default()
    }

    #[wasm_bindgen(getter, js_name = "nodeType")]
    pub fn node_type(&self) -> String {
        self.node_type.to_api_str().to_owned()
    }

    #[wasm_bindgen(setter, js_name = "nodeType")]
    pub fn set_node_type(&mut self, value: WasmNodeType) {
        self.node_type = value;
    }

    #[wasm_bindgen(getter, js_name = "tagName")]
    pub fn tag_name(&self) -> String {
        self.tag_name.clone()
    }

    #[wasm_bindgen(setter, js_name = "tagName")]
    pub fn set_tag_name(&mut self, value: String) {
        self.tag_name = value;
    }

    #[wasm_bindgen(getter)]
    pub fn depth(&self) -> usize {
        self.depth
    }

    #[wasm_bindgen(setter)]
    pub fn set_depth(&mut self, value: usize) {
        self.depth = value;
    }

    #[wasm_bindgen(getter, js_name = "indexInParent")]
    pub fn index_in_parent(&self) -> usize {
        self.index_in_parent
    }

    #[wasm_bindgen(setter, js_name = "indexInParent")]
    pub fn set_index_in_parent(&mut self, value: usize) {
        self.index_in_parent = value;
    }

    #[wasm_bindgen(getter, js_name = "parentTag")]
    pub fn parent_tag(&self) -> Option<String> {
        self.parent_tag.clone()
    }

    #[wasm_bindgen(setter, js_name = "parentTag")]
    pub fn set_parent_tag(&mut self, value: Option<String>) {
        self.parent_tag = value;
    }

    #[wasm_bindgen(getter, js_name = "isInline")]
    pub fn is_inline(&self) -> bool {
        self.is_inline
    }

    #[wasm_bindgen(setter, js_name = "isInline")]
    pub fn set_is_inline(&mut self, value: bool) {
        self.is_inline = value;
    }

    /// Return a reference to the attribute map.
    ///
    /// If the context was built with `NodeContext.with_lazy_attributes`, the
    /// map is materialized on the first call and cached for subsequent calls.
    /// If this method is never called, no allocation occurs for attributes.
    #[wasm_bindgen]
    pub fn attributes(&self) -> JsValue {
        serde_wasm_bindgen::to_value(html_to_markdown_rs::NodeContext::from(self.clone()).attributes())
            .unwrap_or(JsValue::NULL)
    }

    /// Construct a `NodeContext` with an owned attribute map.
    ///
    /// Prefer `NodeContext.with_lazy_attributes` (pub(crate)) inside the
    /// converter to avoid the eager `collect_tag_attributes` allocation.
    #[wasm_bindgen(js_name = "withOwnedAttributes")]
    pub fn with_owned_attributes(
        node_type: WasmNodeType,
        tag_name: String,
        attributes: JsValue,
        depth: usize,
        index_in_parent: usize,
        parent_tag: Option<String>,
        is_inline: bool,
    ) -> WasmNodeContext {
        let node_type_core: html_to_markdown_rs::NodeType = node_type.into();

        let tag_name_converted: std::borrow::Cow<'_, str> = tag_name.into();
        let attributes_converted: std::collections::BTreeMap<String, String> =
            serde_wasm_bindgen::from_value(attributes.clone()).unwrap_or_default();
        let parent_tag_converted = parent_tag.map(Into::into);
        html_to_markdown_rs::NodeContext::with_owned_attributes(
            node_type_core,
            tag_name_converted,
            attributes_converted,
            depth,
            index_in_parent,
            parent_tag_converted,
            is_inline,
        )
        .into()
    }

    /// Promote any borrowed fields into owned storage so the context can outlive `'a`.
    #[wasm_bindgen(js_name = "intoOwned")]
    pub fn into_owned(&self) -> WasmNodeContext {
        html_to_markdown_rs::NodeContext::from(self.clone()).into_owned().into()
    }
}

/// Text directionality of document content.
