/// Result of a visitor callback.
///
/// Allows visitors to control the conversion flow by either proceeding
/// with default behavior, providing custom output, skipping elements,
/// preserving HTML, or signaling errors.

#[wasm_bindgen]
#[derive(Clone, Copy, PartialEq, Eq)]
pub enum WasmVisitResult {
    Continue = 0,
    Custom = 1,
    Skip = 2,
    PreserveHtml = 3,
    Error = 4,
}

#[allow(clippy::derivable_impls)]
impl Default for WasmVisitResult {
    fn default() -> Self {
        Self::Continue
    }
}

impl WasmVisitResult {
    /// Returns the serde wire string for this variant (e.g. `"stop"`, `"tool_calls"`).
    pub fn to_api_str(self) -> &'static str {
        match self {
            Self::Continue => "Continue",
            Self::Custom => "Custom",
            Self::Skip => "Skip",
            Self::PreserveHtml => "PreserveHtml",
            Self::Error => "Error",
        }
    }

    /// Parses a serde wire string and returns the corresponding variant, or None if unrecognized.
    pub fn from_api_str(s: &str) -> Option<Self> {
        match s {
            "Continue" => Some(Self::Continue),
            "Custom" => Some(Self::Custom),
            "Skip" => Some(Self::Skip),
            "PreserveHtml" => Some(Self::PreserveHtml),
            "Error" => Some(Self::Error),
            _ => None,
        }
    }
}

