/// Convert HTML to Markdown, returning a `ConversionResult` with content, metadata, images,
/// and warnings.
///
/// # Arguments
///
/// * `html` — the HTML string to convert.
/// * `options` — conversion options. The parameter bound is
///   `impl Into<Option<ConversionOptions>>`, so any of the following call shapes are accepted:
///   - `convert(html, ConversionOptions.default())` — bare options.
///   - `convert(html, opts)` — bare options.
///   - `convert(html, Some(opts))` — explicit `Option`.
///   - `convert(html, None)` — fall back to `ConversionOptions.default`.
///
/// # Example
///
///
/// # Errors
///
/// Returns an error if HTML parsing fails or if the input contains invalid UTF-8.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen]
pub fn convert(html: String, options: Option<WasmConversionOptions>) -> Result<WasmConversionResult, JsValue> {
    let options_core: Option<html_to_markdown_rs::ConversionOptions> = options.map(Into::into);

    let result = html_to_markdown_rs::convert(&html, options_core).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.into())
}

